import React from "react";
import { Box, Button, Stack } from "@mui/material";
import IconButton from "@mui/material/IconButton";
import Badge from "@mui/material/Badge";
import Menu from "@mui/material/Menu";
import CancelIcon from "@mui/icons-material/Cancel";
import DeleteForeverIcon from "@mui/icons-material/DeleteForever";
import ShoppingCartIcon from "@mui/icons-material/ShoppingCart";
import { useHistory } from "react-router-dom";
import { Messages, serverApi } from "../../../lib/config";
import { useGlobals } from "../../hooks/useGlobals";
import { toastError } from "../../../lib/toastAlert";
import OrderService from "../../../services/OrderService";
import { CartItem } from "../../../lib/types/search";
import "../../../css/basket.css";

interface BasketProps {
  cartItems: CartItem[];
  onAdd: (item: CartItem) => void;
  onRemove: (item: CartItem) => void;
  onDelete: (item: CartItem) => void;
  onDeleteAll: () => void;
}

// ✅ KRW formatter
const krw = new Intl.NumberFormat("ko-KR");

export default function Basket(props: BasketProps) {
  const { cartItems, onAdd, onDelete, onDeleteAll, onRemove } = props;
  const { authMember, setOrderBuilder } = useGlobals();
  const history = useHistory();
  const itemsPrice: number = cartItems.reduce(
    (a: number, c: CartItem) => a + c.quantity * c.price,
    0,
  );
  const shippingCost: number = itemsPrice < 100 ? 5 : 0;
  const totalPrice = itemsPrice + shippingCost;
  const [anchorEl, setAnchorEl] = React.useState<null | HTMLElement>(null);
  const open = Boolean(anchorEl);

  console.log("Basket render:", { anchorEl, open, cartItems });

  /** HANDLERS **/
  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    setAnchorEl(e.currentTarget);
    console.log("Basket clicked", {
      anchorEl: e.currentTarget,
      open: Boolean(e.currentTarget),
    });
  };
  const handleClose = () => {
    setAnchorEl(null);
  };
  const proceedOrderHandler = async () => {
    try {
      handleClose();
      if (!authMember) throw new Error(Messages.error2);

      const order = new OrderService();
      await order.createOrder(cartItems);

      onDeleteAll();
      setOrderBuilder(new Date());
      history.push("/orders");
    } catch (err) {
      console.log();
      toastError(err);
    }
  };

  return (
    <Box className={"hover-line"}>
      <IconButton
        aria-label="cart"
        id="basic-button"
        aria-controls={open ? "basic-menu" : undefined}
        aria-haspopup="true"
        aria-expanded={open ? "true" : undefined}
        onClick={handleClick}
      >
        <Badge badgeContent={cartItems.length} color="secondary">
          <img
            src={"/icons/shopping-cart.svg"}
            style={{
              height: 24,
            }}
          />
        </Badge>
      </IconButton>
      <Menu
        anchorEl={anchorEl}
        id="account-menu"
        open={open}
        onClose={handleClose}
        PaperProps={{
          elevation: 0,
          sx: {
            overflow: "visible",
            filter: "drop-shadow(0px 2px 8px rgba(0,0,0,0.32))",
            mt: 1.5,
            "& .MuiAvatar-root": {
              width: 32,
              height: 32,
              ml: -0.5,
              mr: 1,
            },
            "&:before": {
              content: '""',
              display: "block",
              position: "absolute",
              top: 0,
              right: 14,
              width: 10,
              height: 10,
              bgcolor: "background.paper",
              transform: "translateY(-50%) rotate(45deg)",
              zIndex: 0,
            },
          },
        }}
        transformOrigin={{ horizontal: "right", vertical: "top" }}
        anchorOrigin={{ horizontal: "right", vertical: "bottom" }}
      >
        <Box className="basket-frame">
          <Box className="all-check-box">
            {cartItems.length === 0 ? (
              <div>Cart is empty</div>
            ) : (
              <Stack direction="row" alignItems="center">
                <div>Cart Products:</div>
                <DeleteForeverIcon
                  sx={{ ml: "5px", cursor: "pointer" }}
                  onClick={() => onDeleteAll()}
                  color="primary"
                />
              </Stack>
            )}
          </Box>

          <Box className="orders-main-wrapper">
            <Box className="orders-wrapper">
              {cartItems.map((item: CartItem) => {
                const ImagePath = `${serverApi}/${item.image}`;
                return (
                  <Box className="basket-info-box" key={item._id}>
                    <div className="cancel-btn">
                      <CancelIcon onClick={() => onDelete(item)} />
                    </div>
                    <img src={ImagePath} className="product-img" />
                    <span className="product-name">{item.name}</span>
                    <p className="product-price">
                      ₩{krw.format(item.price)} x {item.quantity}
                    </p>
                    <Box className="col-2">
                      <button onClick={() => onRemove(item)} className="remove">
                        -
                      </button>
                      <button onClick={() => onAdd(item)} className="add">
                        +
                      </button>
                    </Box>
                  </Box>
                );
              })}
            </Box>
          </Box>

          {cartItems.length !== 0 && (
            <Box className="basket-order">
              <span className="price">
                Total: ₩{krw.format(totalPrice)} (₩{krw.format(itemsPrice)}+
                ₩{krw.format(shippingCost)})
              </span>
              <Button
                onClick={proceedOrderHandler}
                startIcon={<ShoppingCartIcon />}
              >
                Order
              </Button>
            </Box>
          )}
        </Box>
      </Menu>
    </Box>
  );
}
